section.code:
{
  "$id": "gateway-fallback-chain/call",
  "type": "object",
  "required": ["model", "messages", "models"],
  "additionalProperties": true,
  "properties": {
    "model":    {"type": "string", "minLength": 1},
    "messages": {"type": "array", "minItems": 1},
    "models": {
      "type": "array",
      "minItems": 2,
      "description": "Ordered fallback chain; the first entry is the primary. Must include >=2 providers.",
      "items": {"type": "string", "pattern": "^[a-z0-9-]+/[a-z0-9.\\-]+$"}
    }
  }
}
